const openAiOutput = ($input.item.json.output?.[0]?.content?.[0]?.text ?? $input.item.json.text ?? "").trim();

// Hole Kundendaten aus dem richtigen vorherigen Node
let customerData = {};

try {
  customerData = $('Format Tally Data').item.json;
} catch(e) {
  try {
    customerData = $('Edit Fields1').item.json;
  } catch(e2) {
    customerData = {};
  }
}

return {
  kategorie: openAiOutput,
  kundenname: (customerData.kundenname ?? "").replace(/^=/, ""),
  email: (customerData.email ?? "").replace(/^=/, ""),
  telefonnummer: (customerData.telefonnummer ?? "").replace(/^=/, ""),
  adresse: (customerData.adresse ?? "").replace(/^=/, ""),
  gebaudetyp: (customerData.gebaudetyp ?? "").replace(/^=/, ""),
  reinigungsservice: (customerData.reinigungsservice ?? "").replace(/^=/, ""),
  quadratmeter: (customerData.quadratmeter ?? "").replace(/^=/, ""),
  service: (customerData.service ?? "").replace(/^=/, "")
};
